// 2.8.1 | 2023-04-07 | raj | STRY0137371 - Icons to Represent Status
// 2.8.5 | 2024-10-14 | RAJ  | STRY0154923 - Workflow Issue - move all updates that require additional processing into an event.  Remove setWorkflow(false) from task object
// Script Continued Below
var TaskerStatus = Class.create();
TaskerStatus.prototype = {
	initialize: function() {
	},

	getStatusAndReason: function(gr_task){
		var status_and_reason = {};
		var daysBeforeSuspenseDateTaskStatusIsWarning = gs.getProperty("x_153465_discovert.#DaysBeforeSuspenseDateTaskStatusIsWarning");		
		var now = new GlideDateTime();
		var dateStatus = "";
		var dateMsg="";
		var riskStatus = "";
		var riskMsg = "";		
		var newTaskStatus = "";   //STRY0071865 & STRY0074351 | 2.5.13 : Variable to get previous status and to be able to send the notification ONLY when Status changes from "Projected on Time" to "Warning" or from "Warning" to "Critical"
		var newReason = "";

		// RAJ 2018-03-13 check supsense date before using
		if(!gr_task.suspense_date.nil()){
			// STRY0102134 - NOTE: below warning hours is really warning days.  The field name is hours, but the label is clearly days
			var warningStartDate = new GlideDate();

			var taskOU = null;
			if(gr_task.getDisplayValue('primary_office') + '' == ''){
				taskOU = new GlideRecord('x_153465_discovert_discover_office_hierarchy');
				if(taskOU.get(gr_task.getValue('primary_office'))){
					// use OU below
				} else {
					taskOU = null;
				}
			}

			var tdc = new TaskerDurationCalculator();
			if(!gr_task.warning_hours.nil()){
				// count from today the number of warning days
				warningStartDate = tdc.calculateDateOfAddedBusinessDays(taskOU, gr_task.warning_hours, warningStartDate);
			} else{
				warningStartDate = tdc.calculateDateOfAddedBusinessDays(taskOU, daysBeforeSuspenseDateTaskStatusIsWarning, warningStartDate);
			}
			var WarningStartTime = warningStartDate.getValue();

			if (now > gr_task.suspense_date){
				dateStatus = "Overdue";
				dateMsg = gs.getMessage("Tasker - Task is Overdue");
			} else {
				// STRY0102134 - above we are adding the number of warning days to today.
				//               This line of code was changed to compare the suspense date to the warning days instead of now to warning days since we are counting forward instead of backward
				if (WarningStartTime > gr_task.suspense_date) {
					dateStatus = "Warning";
					dateMsg = gs.getMessage("Tasker - Task is due in under {0} days", [gr_task.warning_hours]);
				}else{
					dateStatus = "Projected on time";
					dateMsg = "Projected on time";
				}
			}
		} else {
			dateStatus = "No Suspense Date";
		}
		// Pull Risk Information
		if(gr_task.risk_flag==2){
			riskStatus = "High Risk";
			riskMsg = gs.getMessage("Tasker - Task has been marked High Risk");
		} else if (gr_task.risk_flag==1) {
			riskStatus = "Medium Risk";
			riskMsg = gs.getMessage("Tasker - Task has been marked Medium Risk");
		} else if (gr_task.risk_flag==0) {
			riskStatus = "Low Risk";
		}

		//STRY0071865 | 2.5.13 : Set new task status to variable
		if ((dateStatus=="Overdue")  || (riskStatus=="High Risk")){
			newTaskStatus = "Critical";	
		} else if ((dateStatus=="Warning")  || (riskStatus=="Medium Risk")){
			newTaskStatus = "Warning";
		} else {
			newTaskStatus = "Projected on time";
		}

		if(dateMsg != ""){
			newReason = dateMsg;
		}
		if(riskMsg != ""){
			if(dateMsg != ""){
				newReason = dateMsg + " - ";
			} 
			newReason += riskMsg;
		}

		status_and_reason.status = newTaskStatus;
		status_and_reason.reason = newReason;

		return status_and_reason;
	},

	updateTaskerStatus : function(strquery){
		var statusAndReason = {};
		var newTaskStatus = "";   //STRY0071865 & STRY0074351 | 2.5.13 : Variable to get previous status and to be able to send the notification ONLY when Status changes from "Projected on Time" to "Warning" or from "Warning" to "Critical"
		var gr = new GlideRecord('x_153465_discovert_route_task_instance');
		if (!strquery) gr.addEncodedQuery('active=true^status!=Critical'); else gr.addEncodedQuery(strquery);
		gr.query();			
		while(gr.next()) {
			statusAndReason = this.getStatusAndReason(gr);
			newTaskStatus = statusAndReason.status;
			//STRY0071865 & STRY0074351 | 2.5.13 : Variable to get previous status and to be able to send the notification ONLY when Status changes from "Projected on Time" to "Warning" or from "Warning" to "Critical"
			if (gr.getValue('status') != newTaskStatus){
				gr.status = newTaskStatus;
				gr.update();
			}
		}
	},

		type: 'TaskerStatus'
	};
